+    };
+
+    let title_token = if let Some(ref title) = config.title {
+        quote::quote! { Some(#title) }
+    } else {
+        quote::quote! { None }
+    };
+
+    quote::quote! {
+        sqlmodel_core::ModelConfig {
+            table: #table,
+            from_attributes: #from_attributes,
